const reviewContent=$('Analyze PR').first().json;
const existingComments=$input.all().map(i=> i.json).filter(i=> i.body);
const discordPayload=reviewContent.discordPayload;
const slackPayload=reviewContent.slackPayload;
const telegramPayload=reviewContent.telegramPayload;

const prNumber=reviewContent.prNumber;
const repoFullName=reviewContent.repoFullName;

let existingCommentId=null;
for (const comment of existingComments) {
  if(comment.body.includes("<!-- pr-auto-reviewer-v1 -->")){
  existingCommentId=comment.id;
    break;
  }
}

const timestamp = $now.setZone('Asia/Kolkata').toFormat('yyyy-MM-dd HH:mm');

const finalBody=`<!-- pr-auto-reviewer-v1 -->\n${reviewContent.reviewContent}\n*Last updated*: ${timestamp}`;

return [{
  json: {
    exists: existingCommentId!==null,
    commentId: existingCommentId,
    commentBody: finalBody,
    discordPayload,
    slackPayload,
    telegramPayload,
    prNumber,
    repoFullName
  }
}];

const pr=$('GitHub Webhook (PR Events)').first().json.body.pull_request;
const prNumber=$('GitHub Webhook (PR Events)').first().json.body.number;
const rawInput = $input.all();
const files = rawInput.length > 0 && rawInput[0].json.filename ? rawInput.map(i => i.json) : [];

const prTitle=pr.title;
const validPrefixes = ['feat:', 'fix:', 'docs:', 'style:', 'refactor:', 'test:', 'chore:', 'perf:', 'ci:', 'build:'];

let titleCheck='❌ Title format unclear';
for (const prefix of validPrefixes) {
  if(prTitle.toLowerCase().startsWith(prefix))
  {
    titleCheck='✅ Follows conventional commit format';
    break;
  }
}

let sizeCategory='N/A';
let uniqueExtensions=[];
let sensitiveBlock='N/A';
let totalChange;
let sensitiveFiles=[];

 if(files.length!==0) {
   const sensitivePatterns = [
  'package.json',
  'package-lock.json',
  'yarn.lock',
  '.env',
  '.env.local',
  '.env.production',
  'requirements.txt',
  'Dockerfile',
  'docker-compose.yml',
  '.github/workflows',  // CI/CD files
];

 sensitiveFiles=files.filter(i=> i.filename&&sensitivePatterns.some(pattern=> i.filename.includes(pattern))).map(f=>f.filename);

 sensitiveBlock = (sensitiveFiles && sensitiveFiles.length > 0) 
    ? `---\n⚠️ **Sensitive files modified:**\n\n${sensitiveFiles.map(f => `- \`${f}\``).join('\n')}` 
    : "✅ No sensitive files touched";

const extension=files.length>0 ? files.map(i=> {
  const parts=i.filename.split('.');
  return parts.length>1 ? '.'+parts.at(-1):'(no ext)';
}):[];

  uniqueExtensions=[...new Set(extension)];

 totalChange= pr.additions+pr.deletions ;

if(totalChange<50) sizeCategory='🟢 Small';
else if(totalChange<200) sizeCategory='🟡 Medium';
else if(totalChange<500) sizeCategory='🟠 Large';
else sizeCategory='🔴 Very Large'; 

 }
 else
   sensitiveBlock = "✅ No sensitive files touched";

let embedColor;
   if(sensitiveFiles.length>0)
     embedColor = 15158332; //red
   else if(sizeCategory.includes('Small'))
     embedColor=3066993; //green
   else if(sizeCategory.includes('Medium'))
     embedColor=15844367; //yellow
   else if(sizeCategory.includes('Very Large'))
     embedColor=11012393; //deep red/purple
   else if(sizeCategory.includes('Large'))
     embedColor=15105570; //orange
   else 
     embedColor=3447003; //blue default

const sensitiveEmbedValue = sensitiveFiles.length > 0
  ?`⚠️ Touched:\n${sensitiveFiles.map(f => `• ${f}`).join('\n')}`
  : '✅ None touched';

 const embedFields=[{name: 'Title Format',value: titleCheck, inline:false}];

if(files.length>0) {
  embedFields.push({ name:'Size', value: sizeCategory,inline:true });
  embedFields.push({ name: 'Files Changed', value: String(files.length), inline:true});
  embedFields.push({name: 'File Types', value:uniqueExtensions.join(', '), inline:true});
  embedFields.push({name: 'Sensitive Files', value: sensitiveEmbedValue, inline:false}); 
}

const embed={
  title:pr.title,
  url: pr.html_url,
  color: embedColor,
  description: `New PR by **${pr.user.login}**`,
  fields: embedFields,
  footer: {text: 'PR Auto-Reviewer'},
  timestamp: new Date().toISOString()
};
  const discordPayload={embeds: [embed]};

let slackColor;
if (sensitiveFiles.length > 0) slackColor = '#E74C3C';
else if (sizeCategory.includes('Very Large')) slackColor = '#922B21';
else if (sizeCategory.includes('Large')) slackColor = '#E67E22';
else if (sizeCategory.includes('Medium')) slackColor = '#F1C40F';
else if (sizeCategory.includes('Small')) slackColor = '#2ECC71';
else slackColor = '#3498DB';

const fileLines=files.map(f=> `- \`${f.filename}\` (${f.status}): +${f.additions}/-${f.deletions}`).join('\n');

// Slack limits headers to 150 characters. This prevents crashes!
const safeTitle = pr.title.length > 150 ? pr.title.substring(0, 147) + '...' : pr.title;

const slackPayload = {
  attachments: [
    {
      color: slackColor,
      blocks: [
        {
          type: "header",
          text: {
            type: "plain_text",
            text: safeTitle,
            emoji: true
          }
        },
        {
          type: "context",
          elements: [
            {
              type: "mrkdwn",
              text: `Opened by <https://github.com/${pr.user.login}|@${pr.user.login}>`
            }
          ]
        },
        {
          type: "divider"
        },
        {
          type: "section",
          text: {
            type: "mrkdwn",
            text: `*Title Format*\n${titleCheck}`
          }
        },
        ...(files.length > 0 ? [
          {
            type: "section",
            fields: [
              {
                type: "mrkdwn",
                text: `*Size*\n${sizeCategory} (${totalChange} lines)`
              },
              {
                type: "mrkdwn",
                text: `*Files Changed*\n${String(files.length)}`
              },
              {
                type: "mrkdwn",
                text: `*File Types*\n${uniqueExtensions.join(', ')}`
              },
              {
                type: "mrkdwn",
                text: `*Sensitive Files*\n${sensitiveEmbedValue}`
              }
            ]
          },
          {
            type: "divider"
          },
          {
            type: "section",
            text: {
              type: "mrkdwn",
              text: `*Per-File Breakdown*\n${fileLines || '_No files_'}`
            }
          }
        ] : [
          {
            type: "section",
            text: {
              type: "mrkdwn",
              text: "_No files to analyze for this event_"
            }
          }
        ]),
        {
          type: "actions",
          elements: [
            {
              type: "button",
              text: {
                type: "plain_text",
                text: "View Pull Request",
                emoji: true
              },
              url: pr.html_url,
              style: "primary"
            }
          ]
        },
        {
          type: "context",
          elements: [
            {
              type: "mrkdwn",
              text: `n8n Auto-Reviewer • ${$now.setZone('Asia/Kolkata').toFormat('yyyy-MM-dd HH:mm')} IST`
            }
          ]
        }
      ]
    }
  ]
};

const telegramFileRows = files.map(f =>
  `<tr><td><code>${f.filename}</code></td><td>${f.status}</td><td>+${f.additions}/-${f.deletions}</td></tr>`
).join('');

const telegramSensitiveBlock = sensitiveFiles.length > 0
  ? `<blockquote>⚠️ <b>Sensitive Files Touched</b><br>${sensitiveFiles.map(f => `• <code>${f}</code>`).join('<br>')}</blockquote>`
  : `<p>✅ <b>Sensitive Files:</b> None touched</p>`;

const telegramFilesSection = files.length > 0 ? `
<h2>Size</h2>
<p>${sizeCategory} — ${totalChange} lines changed</p>
<h2>Per-File Breakdown</h2>
<table>
  <tr><th>File</th><th>Status</th><th>Changes</th></tr>
  ${telegramFileRows}
</table>
<h2>File Types</h2>
<p>${uniqueExtensions.join(', ')}</p>
<h2>Sensitive Files</h2>
${telegramSensitiveBlock}
` : `<p><i>No files to analyze for this event</i></p>`;

const telegramRichHtml = `
<h1>🤖 PR Auto-Review</h1>
<p><a href="${pr.html_url}">${pr.title}</a><br>Opened by <b><a href="https://github.com/${pr.user.login}">@${pr.user.login}</a></b></p>
<h2>Title Format</h2>
<p>${titleCheck}</p>
${telegramFilesSection}
<p><i>n8n Auto-Reviewer • ${$now.setZone('Asia/Kolkata').toFormat('yyyy-MM-dd HH:mm')} IST</i></p>
`;

const telegramPayload = {

  rich_message: { html: telegramRichHtml }
};

const filesBreakdown = files.length !== 0 
    ? `\n**Size:** ${sizeCategory} (${totalChange} lines)\n**Changes:**\n${fileLines}\n\n**Files Changed:** ${files.length}\n**File Types:** ${uniqueExtensions.join(', ')}\n\n${sensitiveBlock}\n\n`
    : '';

const markDownComment=`## 🤖 PR Auto-Review\n\n**Title Format:** ${titleCheck}${filesBreakdown}---\n*Posted by your n8n PR Auto-Reviewer*`;

return {
  json: {
    reviewContent: markDownComment,
    discordPayload,
    slackPayload,
    telegramPayload,
    prNumber,
    repoFullName: $('GitHub Webhook (PR Events)').first().json.body.repository.full_name
  }
};

const crypto = require('crypto');

const secret = $env.GITHUB_WEBHOOK_SECRET;
const githubSignature = $input.item.json.headers['x-hub-signature-256'];
const rawBody = Buffer.from($input.item.binary.data.data, 'base64').toString('utf8');

if (!githubSignature) {
  throw new Error('401: Missing x-hub-signature-256 header');
}

if (!secret) {
  throw new Error('500: GITHUB_WEBHOOK_SECRET env var not set');
}

const expectedSignature = 'sha256=' + crypto
  .createHmac('sha256', secret)
  .update(rawBody)
  .digest('hex');

if (!crypto.timingSafeEqual(
  Buffer.from(expectedSignature, 'utf8'),
  Buffer.from(githubSignature, 'utf8')
)) {
  throw new Error('401: Signature mismatch — payload rejected');
}

return $input.all();
